import { dialog } from "./blockly";

// Former goog.module ID: Blockly.dialog

let alertImplementation = function (
  message: string,
  opt_callback?: () => void,
) {
  window.alert(message);
  if (opt_callback) {
    opt_callback();
  }
};

let confirmImplementation = function (
  message: string,
  callback: (result: boolean) => void,
) {
  callback(window.confirm(message));
};

let promptImplementation = function (
  message: string,
  defaultValue: string,
  callback: (result: string | null) => void,
) {
  callback(window.prompt(message, defaultValue));
};

/**
 * Wrapper to window.alert() that app developers may override via setAlert to
 * provide alternatives to the modal browser window.
 *
 * @param message The message to display to the user.
 * @param opt_callback The callback when the alert is dismissed.
 */
export function alert(message: string, opt_callback?: () => void) {
  alertImplementation(message, opt_callback);
}

/**
 * Sets the function to be run when Blockly.dialog.alert() is called.
 *
 * @param alertFunction The function to be run.
 * @see Blockly.dialog.alert
 */
export function setAlert(alertFunction: (p1: string, p2?: () => void) => void) {
  alertImplementation = alertFunction;
}

/**
 * Wrapper to window.confirm() that app developers may override via setConfirm
 * to provide alternatives to the modal browser window.
 *
 * @param message The message to display to the user.
 * @param callback The callback for handling user response.
 */
export function confirm(message: string, callback: (p1: boolean) => void) {
  TEST_ONLY.confirmInternal(message, callback);
}

/**
 * Private version of confirm for stubbing in tests.
 */
function confirmInternal(message: string, callback: (p1: boolean) => void) {
  confirmImplementation(message, callback);
}

/**
 * Sets the function to be run when Blockly.dialog.confirm() is called.
 *
 * @param confirmFunction The function to be run.
 * @see Blockly.dialog.confirm
 */
export function setConfirm(
  confirmFunction: (p1: string, p2: (p1: boolean) => void) => void,
) {
  confirmImplementation = confirmFunction;
}

/**
 * Wrapper to window.prompt() that app developers may override via setPrompt to
 * provide alternatives to the modal browser window. Built-in browser prompts
 * are often used for better text input experience on mobile device. We strongly
 * recommend testing mobile when overriding this.
 *
 * @param message The message to display to the user.
 * @param defaultValue The value to initialize the prompt with.
 * @param callback The callback for handling user response.
 */
export function prompt(
  message: string,
  defaultValue: string,
  callback: (p1: string | null) => void,
) {
  promptImplementation(message, defaultValue, callback);
}

/**
 * Sets the function to be run when Blockly.dialog.prompt() is called.
 *
 * @param promptFunction The function to be run.
 * @see Blockly.dialog.prompt
 */
export function setPrompt(
  promptFunction: (
    p1: string,
    p2: string,
    p3: (p1: string | null) => void,
  ) => void,
) {
  promptImplementation = promptFunction;
}

export const TEST_ONLY = {
  confirmInternal,
};

/* 自定义弹框 */
export function ShowCustomDialog(title: string, options: any) {
  let backdropDiv = document.getElementById('customDialogBackdrop') || null
  let dialogDiv = document.getElementById('customDialog') || null
  if (!dialogDiv) {
    // Generate HTML
    backdropDiv = document.createElement('div')
    backdropDiv.id = 'customDialogBackdrop'
    backdropDiv.style.cssText = 
      'position: absolute;' +
      'top: 0; left: 0; right: 0; bottom: 0;' +
      'background-color: rgba(0, 0, 0, 0.7);' +
      'z-index: 1112;';

    dialogDiv = document.createElement('div')
    dialogDiv.id = 'customDialog'
    dialogDiv.style.cssText = 
      'position: relative;' +
      'display: block;' +
      'width: 374px;' +
      'height: 203px;' +
      'margin: 300px auto;' +
      'border: 1px solid #D9D9D9;' +
      'border-radius: 6px;' +
      'padding: 24px;' +
      'background-color: rgb(255, 255, 255);' +
      'box-sizing: border-box;'
    backdropDiv.appendChild(dialogDiv)
    document.body.appendChild(backdropDiv)

    dialogDiv.onclick = function(event) {
      event.stopPropagation()
    }
  }

  dialogDiv.innerHTML =
    '<header class="customDialogTitle" style="font-size: 14px; color: #999999;"></header>' +
    '<img class="variables-close" style="position: absolute; top: 10px; right: 12px; width: 24px; height: 24px" src="data:image/png;base64," alt="">' +
    (options.showInput ? '<div style="margin: 27px 0 37px 0; text-align: center;"><input id="customDialogInput" style="border: none; text-align: center; outline: aliceblue; color: #666666; font-size: 20px;"></div>' : '') +
    '<div style="width: 293px; height: 1px; margin: 0 auto; background: #e6e1d4;"></div>' +
    '<div class="customDialogButtons" style="position: absolute; right: 24px; bottom: 24px">' +
    (options.showCancel ? '<button id="customDialogCancel" style="width: 64px; height: 32px; background: #f2f2f2; border-radius: 4px; font-size: 14px; color: #bbbbbb; border: none; margin: 0 8px 0 0">取消</button>': '') +
    (options.showOkay ? '<button id="customDialogOkay" style="width: 64px; height: 32px; background: #fadf75; border-radius: 4px; font-size: 14px; color: #CE8137; border: none;">确认</button>': '') +
    '</div>';

  dialogDiv.getElementsByClassName('customDialogTitle')[0]
    .appendChild(document.createTextNode(title))
  
  let onOkay = function(event: any) {
    options.onOkay();
    event && event.stopPropagation();
    HideCustomDialog()
  }
  let onCancel = function(event: any) {
    options.onCancel();
    event && event.stopPropagation();
    HideCustomDialog()
  }

  let dialogInput = document.getElementById('customDialogInput')
  if (dialogInput) {
    dialogInput.focus();

    dialogInput.onkeyup = function(event: any) {
      if (event.key === 'Enter') {
        // Process as Ok when user hits enter
        onOkay(event)
        return false
      } else if (event.key === 'Escape') {
        // Process as cancel when user hits esc.
        onCancel(event)
        return false
      }
    }
  } else {
    let okay = document.getElementById('customDialogOkay')
    okay && okay.focus()
  }

  if (options.showOkay) {
    document.getElementById('customDialogOkay')
      ?.addEventListener('click', onOkay)
  }

  if (options.showCancel) {
    document.getElementById('customDialogCancel')
      ?.addEventListener('click', onCancel)
    
    document.getElementsByClassName('variables-close')[0]
      ?.addEventListener('click', onCancel)
  }

  if (backdropDiv) backdropDiv.onclick = onCancel;
}
export function HideCustomDialog() {
  let box = document.getElementById('customDialogBackdrop')
  if (box) document.body.removeChild(box)
}
